package com.evolua.chat.interfaces.rest; import com.evolua.chat.application.MessageService; import com.evolua.chat.infrastructure.security.CurrentUserProvider; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import java.util.List; import org.springframework.http.HttpStatus; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/v1/messages") public class MessageController { private final MessageService service; private final MessageMapper mapper; private final CurrentUserProvider currentUserProvider; public MessageController(MessageService service, MessageMapper mapper, CurrentUserProvider currentUserProvider) { this.service = service; this.mapper = mapper; this.currentUserProvider = currentUserProvider; } @PostMapping @Operation(summary = "Create Message") public ResponseEntity<ApiResponse<MessageResponse>> create(@Valid @RequestBody MessageRequest request) { var created = service.create(currentUserProvider.getCurrentUser().userId(), request.recipientId(), request.content()); return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(201, "Created", mapper.toResponse(created))); } @GetMapping @Operation(summary = "List messages") public ResponseEntity<ApiResponse<List<MessageResponse>>> list() { return ResponseEntity.ok(ApiResponse.success(200, "Listed", service.list(currentUserProvider.getCurrentUser().userId()).stream().map(mapper::toResponse).toList())); } }
